impl Solution { pub fn queens_attackthe_king(queens: Vec<Vec<i32>>, king: Vec<i32>) -> Vec<Vec<i32>> { let mut black_q = std::collections::HashSet::new(); for q in queens { black_q.insert((q[0], q[1])); } let mut black_res = vec![]; for dx in -1..=1 { for dy in -1..=1 { if dx == 0 && dy == 0 { continue; } let (mut x, mut y) = (king[0], king[1]); while x >= 0 && x < 8 && y >= 0 && y < 8 { if black_q.contains(&(x, y)) { black_res.push(vec![x, y]); break; } x += dx; y += dy; } } } black_res } }